// Parse Claude JSON and build Supabase payload
const llmText = $input.first().json.text || '';

let parsed;
try {
  // Remove markdown code fences if present
  const clean = llmText
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  parsed = JSON.parse(clean);
} catch(e) {
  // Try to find JSON object in the text
  const match = llmText.match(/\{[\s\S]*\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch(e2) { throw new Error('No se pudo parsear la respuesta: ' + llmText.slice(0, 300)); }
  } else {
    throw new Error('No se encontró JSON en la respuesta: ' + llmText.slice(0, 300));
  }
}

// No Beezion tasks found? Skip gracefully
if (!parsed.tasks || parsed.tasks.length === 0) {
  return [{ json: { skipped: true, reason: 'No hay tareas de Beezion en esta reunión', meeting_title: parsed.meeting_title } }];
}

// Build Supabase-ready payload
return [{
  json: {
    meeting_title: parsed.meeting_title || 'Reunión',
    meeting_date: parsed.meeting_date || new Date().toISOString().slice(0, 10),
    transcript: '',
    tasks: parsed.tasks.map(t => ({
      title: t.title,
      client_name: parsed.client_name || null,
      area: t.area || 'copy',
      assignee: t.assignee || 'Alejandro',
      priority: t.priority || 'media',
      week: parseInt(t.week) || 1,
      tipo: t.tipo || 'nuevo',
      problema: t.problema || null
    }))
  }
}];

// No Beezion tasks — log and exit cleanly
console.log('Reunión sin tareas de Beezion:', $json.meeting_title);
return [{ json: { status: 'skipped', meeting: $json.meeting_title || 'unknown' } }];
